INSERT INTO `menu` (`id`, `title`, `category_id`, `image`, `description`, `price`, `delivery`, `status`, `created_at`) VALUES
(6, 'Chicken Biryani', 5, '1755250239_biryani.jpg', 'Our Chicken Biryani is a flavorful blend of tender, marinated chicken, fragrant basmati rice, and authentic spices. Slow-cooked to perfection, it delivers rich aroma, bold taste, and a truly satisfying experience in every bite.', 8, 2, 1, '2025-08-15 09:30:39'),
(7, 'Beef Biryani', 5, '1755250363_image.webp', 'Our Beef Biryani is a hearty and aromatic dish made with succulent beef, long-grain basmati rice, and a blend of traditional spices. Cooked to perfection, it offers deep, rich flavors and a satisfying taste in every mouthful.', 13, 2, 1, '2025-08-15 09:32:43'),
(8, 'Chicken Korma', 4, '1755250451_chicken-korma-recipe.jpg', 'Our Chicken Korma is a creamy, flavorful curry made with tender chicken simmered in a rich blend of yogurt, spices, and nuts. It\\&#039;s smooth, aromatic, and perfect for those who love mild yet deeply satisfying flavors.', 10, 2, 1, '2025-08-15 09:34:11'),
(9, 'Makhni chicken handi', 4, '1755250603_Chicken-Makhani-achari-handi-Recipe-by-Food-fusion-3.webp', 'Our Makhni Chicken Handi is a rich and buttery curry made with tender chicken cooked in a creamy tomato-based gravy. Infused with aromatic spices, it&rsquo;s smooth, flavorful, and melts in your mouth with every bite.', 12, 2, 1, '2025-08-15 09:36:43'),
(10, 'Reshmi Kebab', 7, '1755250805_Chicken-Reshmi-Kebabs-FB.jpg', 'Our Reshmi Kebab is a soft, juicy, and mildly spiced grilled delicacy made from marinated chicken. Cooked to perfection, it&amp;rsquo;s creamy, tender, and bursting with smoky flavor in every bite.', 10, 2, 1, '2025-08-15 09:40:05'),
(11, 'Malai Boti Roll', 7, '1755251020_malaibotti.jpg', 'Our Malai Boti Roll features tender, creamy chicken malai boti wrapped in a soft paratha with chutney and onions. It&rsquo;s rich, flavorful, and perfect for a delicious on-the-go meal.', 10, 2, 1, '2025-08-15 09:43:40'),
(12, 'Zarda', 5, '1755251143_zarda.jpg', 'Our Zarda Rice is a sweet and fragrant dessert rice cooked with saffron, sugar, and aromatic spices, garnished with colorful nuts and dried fruits. It&rsquo;s a delightful and vibrant treat for any occasion.', 10, 2, 1, '2025-08-15 09:45:43'),
(13, 'Kheer', 6, '1755251227_Rice-Kheer-Indian-Rice-Pudding44.webp', 'Our Kheer is a creamy, traditional rice pudding made with slow-cooked milk, fragrant rice, and cardamom, sweetened to perfection and garnished with nuts. It&rsquo;s a rich, comforting dessert loved by all.', 10, 2, 1, '2025-08-15 09:47:07'),
(14, 'Rasgullah', 6, '1755251411_rasgullah.jpg', 'Our Rasgulla is a soft and spongy Indian dessert made from fresh cheese balls soaked in sweet, fragrant syrup. Light, juicy, and delightfully refreshing with every bite.', 5, 2, 1, '2025-08-15 09:50:11');

